mapper.select:
SELECT c.customer_id AS id, c.customer_name AS customerName, c.age AS age, c.gender AS gender, c.date_of_birth AS dateOfBirth, c.id_number AS idNumber, c.blood_type AS bloodType, c.family_member AS familyMember, c.tel AS tel, c.nation, c.family_member_tel, r.building AS buildingNumber, r.room_no AS roomNumber, b.bed_no AS bedNumber, s.user_name AS caregiver, c.check_in_date AS checkInDate, c.contract_end_date AS contractEndDate, c.physical_mental_status AS physicalMentalStatus, l.nursing_level_name AS nursingLevel, c.nursing_level_id AS levelId, c.customer_type AS customerType FROM customer c LEFT JOIN bed b ON c.bed_id = b.bed_id LEFT JOIN room r ON b.room_id = r.room_id LEFT JOIN user s ON c.user_id = s.user_id LEFT JOIN nursing_level l ON c.nursing_level_id = l.nursing_level_id
AND c.customer_name LIKE CONCAT('%', #{customerName}, '%')
AND c.customer_type = #{customerType}
AND c.del_flag = '0' AND c.history = '1'
order by c.customer_id desc LIMIT #{pageStart}, #{pageSize}

mapper.update:
UPDATE customer
SET del_flag = 1
WHERE customer_id = #{id}

mapper.select:
SELECT p.nursing_item_record_id AS id, c.customer_name AS customerName, n.code AS code, p.nursing_item_name AS name, p.execution_times AS executionTimes, p.purchasing_times*p.execution_times-p.executed_times AS remain, p.expiration_date AS expireDate, CASE WHEN NOW() > p.expiration_date THEN 'expired' ELSE 'normal' END AS status FROM nursing_item_record p LEFT JOIN customer c ON p.customer_id = c.customer_id LEFT JOIN nursing_item n ON p.nursing_item_name = n.nursing_item_name WHERE p.customer_id = #{customerId} AND p.del_flag = '0'
AND n.nursing_item_name LIKE CONCAT('%', #{itemName}, '%')
ORDER BY p.nursing_item_record_id DESC LIMIT #{pageStart}, #{pageSize}

SELECT COUNT(*) FROM nursing_item_record p WHERE p.customer_id = #{customerId}
AND n.nursing_item_name LIKE CONCAT('%', #{itemName}, '%')
AND p.del_flag = '0'

SELECT COUNT(*)
FROM nursing_item_record p
LEFT JOIN nursing_item n ON p.nursing_item_name = n.nursing_item_name
WHERE p.customer_id = #{customerId}
AND n.nursing_item_id = #{itemId}
AND p.del_flag = '0'

